                reg_tile[6][1] += dev_t3[t3_base_thread + (6 * stride_reg_y) + (1 * stride_reg_x)];
                reg_tile[6][2] += dev_t3[t3_base_thread + (6 * stride_reg_y) + (2 * stride_reg_x)];
                reg_tile[6][3] += dev_t3[t3_base_thread + (6 * stride_reg_y) + (3 * stride_reg_x)];

