                reg_tile[7][1] += dev_t3[t3_base_thread + (7 * stride_reg_y) + (1 * stride_reg_x)];
                reg_tile[7][2] += dev_t3[t3_base_thread + (7 * stride_reg_y) + (2 * stride_reg_x)];
                reg_tile[7][3] += dev_t3[t3_base_thread + (7 * stride_reg_y) + (3 * stride_reg_x)];
