  rest_y=rest_y/h2d;
  h3_0=rest_x%h3d;
  rest_x=rest_x/h3d;
  h1_0=rest_y%h1d;
  rest_y=rest_y/h1d;
  p4_0=rest_y;
  p6_0=rest_x;
  rest_x = T2 *4* blockIdx.x + threadIdx.x+T1*1;
  rest_y = T1 *4* blockIdx.y + threadIdx.y+T1*1;
