  rest_y=rest_y/h2d;
  h3_1=rest_x%h3d;
  rest_x=rest_x/h3d;
  h1_1=rest_y%h1d;
  rest_y=rest_y/h1d;
  p4_1=rest_y;
  p6_1=rest_x;
  rest_x = T2 *4* blockIdx.x + threadIdx.x+T1*2;
  rest_y = T1 *4* blockIdx.y + threadIdx.y+T1*2;
  h2_2=rest_y%h2d;
  rest_y=rest_y/h2d;
  h3_2=rest_x%h3d;
  rest_x=rest_x/h3d;
  h1_2=rest_y%h1d;
  rest_y=rest_y/h1d;
  p4_2=rest_y;
