  h1_3=rest_y%h1d;
  rest_y=rest_y/h1d;
  p4_3=rest_y;
  p6_3=rest_x;
  int t2_d_off, v2_d_off;for(p7T=0;p7T<p7d;p7T+=Tcomm){int p7l_hi;
    p7l_hi = MIN(Tcomm+p7T,p7d)-p7T;
    t2_d_off=p4_0*p4ld_t2+h1_0*h1ld_t2+h2_0*h2ld_t2;
