      a2=t2_shm[in1_idxl+T1*1][p7l];
      a3=t2_shm[in1_idxl+T1*2][p7l];
      a4=t2_shm[in1_idxl+T1*3][p7l];
      b1=v2_shm[p7l][in2_idxl+T2*0];
      b2=v2_shm[p7l][in2_idxl+T2*1];
      b3=v2_shm[p7l][in2_idxl+T2*2];
      b4=v2_shm[p7l][in2_idxl+T2*3];
      tlocal1+=a1*b1;
      tlocal2+=a2*b1;
      tlocal3+=a3*b1;
      tlocal4+=a4*b1;
      tlocal5+=a1*b2;
      tlocal6+=a2*b2;
      tlocal7+=a3*b2;
      tlocal8+=a4*b2;
      tlocal9+=a1*b3;
      tlocal10+=a2*b3;
      tlocal11+=a3*b3;
      tlocal12+=a4*b3;
