  rest_y=rest_y/h2d;
  h1_1=rest_y%h1d;
  rest_y=rest_y/h1d;
  p6_1=rest_x%p6d;
  rest_x=rest_x/p6d;
  p4_1=rest_y;
  p5_1=rest_x;
  rest_x = T2 *4* blockIdx.x + threadIdx.x+T1*2;
  rest_y = T1 *4* blockIdx.y + threadIdx.y+T1*2;
  h3_2=rest_x%h3d;
