  assert(streams!= NULL);
  for(i=0;i<nstreams;++i) {
    CUDA_SAFE(cudaStreamCreate(&streams[i])) ;
  }
  CUDA_SAFE(cudaMemcpy(t2_d,t2,size_t2,cudaMemcpyHostToDevice));
  CUDA_SAFE(cudaMemcpy(v2_d,v2,size_v2,cudaMemcpyHostToDevice));
