		stream++;
	}
*/
	cudaThreadSynchronize();

//	CUDA_SAFE(cudaMemcpy(((char *) t3) , ((char *) t3_s_d) , size_t3, cudaMemcpyDeviceToHost));
	for (i = 0; i < nstreams; ++i) {
		cudaStreamDestroy(streams[i]);
	}
//	freeGpuMem(t3_d);
	freeGpuMem(t2_d);
	freeGpuMem(v2_d);
   //  cudaFree(t2_d);
   //  cudaFree(v2_d);
	freeHostMem(t3_p);
	free(streams);
}
